mapper.select:
SELECT n.* FROM t_notice n WHERE n.notice_push_type = #{queryForm.noticePushType} AND n.deleted_flag = #{queryForm.deletedFlag}
AND ( INSTR(n.title, #{queryForm.keywords}) OR INSTR(n.source, #{queryForm.keywords}) OR INSTR(n.author, #{queryForm.keywords}) OR INSTR(n.document_number, #{queryForm.keywords}) )
ORDER BY n.publish_time DESC, n.notice_id DESC

SELECT *
FROM t_notice n
WHERE n.notice_id = #{noticeId} AND n.notice_push_type = #{pushType}

SELECT count(*)
FROM t_notice_view_record
WHERE notice_id = #{noticeId} AND employee_id = #{driverId}

mapper.update:
UPDATE t_notice
SET page_view_count = page_view_count + #{increasePageViewCount},
    user_view_count = user_view_count + #{increaseUserViewCount}
WHERE notice_id = #{noticeId}

UPDATE t_notice_view_record
SET last_ip = #{ip}, last_user_agent = #{userAgent}, page_view_count = page_view_count + #{viewCount}
WHERE notice_id = #{noticeId} AND employee_id = #{driverId}
